import os
import json
import boto3
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.options import Options

app = Flask(__name__)

s3_client = boto3.client('s3')
BUCKET_NAME = 'your-s3-bucket-name'

def take_screenshot(url):
    chrome_options = Options()
    chrome_options.add_argument("--headless")
    chrome_options.add_argument("--no-sandbox")
    chrome_options.add_argument("--disable-dev-shm-usage")
    
    driver = webdriver.Chrome(options=chrome_options)
    driver.get(url)
    screenshot = driver.get_screenshot_as_png()
    driver.quit()
    
    return screenshot

def upload_to_s3(screenshot, url):
    filename = f"{url.replace('http://', '').replace('https://', '').replace('/', '_')}.png"
    s3_client.put_object(Bucket=BUCKET_NAME, Key=filename, Body=screenshot, ContentType='image/png')
    return f"https://{BUCKET_NAME}.s3.amazonaws.com/{filename}"

@app.route('/screenshot', methods=['POST'])
def screenshot():
    data = request.json
    url = data.get('url')
    
    if not url:
        return jsonify({'error': 'URL is required'}), 400
    
    screenshot = take_screenshot(url)
    s3_url = upload_to_s3(screenshot, url)
    
    return jsonify({'screenshot_url': s3_url}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=int(os.environ.get('PORT', 5000)))